const { complaintId, userEmail, complaintText, category, priority, location } = $input.item.json.body || {};

if (!complaintId || !userEmail || !complaintText) {
  throw new Error("Missing required complaint fields (ID, Email, or Text)");
}

return {
  complaintId,
  userEmail,
  complaintText,
  category: category || 'General',
  priority: priority || 'Medium',
  location: location || 'Unknown',
  authorityEmail: 'cmpunktg5@gmail.com'
};
